	for(int l=2;l<=n;l++)
	{
		int ans=mod1;
		for(int i=1;i<=n-l+1;i++)
		{
			int j=i+l-1;
			dp[i][j]=dp[i+1][j-1]+abs(h[i]-h[j]);
            ans=min(ans,dp[i][j]);
		}
		cout<<ans<<" ";
	}
	return 0;
}





